  (id, slug, scope, lesson_id, module_id, level, title, description, question_count, pass_threshold, cooldown_hours, status) values
  ($lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, $lum$working-well-with-ai-module-check$lum$, $lum$module$lum$, NULL, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, NULL, $lum$Working well with AI: test out$lum$, $lum$Already verify AI output, protect privacy, and use AI with integrity at work? Pass this and the whole Working well with AI module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published'),
  ($lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, $lum$responsibility-and-judgment-module-check$lum$, $lum$module$lum$, NULL, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, NULL, $lum$Responsibility & judgment: test out$lum$, $lum$Already keep your judgment in charge, disclose AI use appropriately, and own the results? Pass this and the whole Responsibility & judgment module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published')
