insert into mastery_check_questions
  (id, check_id, order_index, type, content, source_block_id) values
  ($lum$5fa8d04a-db03-5f3b-b294-08235ba6b8f6$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"AI gives you a confident answer with a specific statistic and a source. What is the right move before you use it?","options":[{"id":"a","label":"Trust it, since it named a source","is_correct":false,"explanation":"AI invents plausible sources and numbers. A named source is not proof the fact is real."},{"id":"b","label":"Verify the statistic and the source against the original before relying on it","is_correct":true,"explanation":"Confident and specific is exactly when to check. Confirm it against the real source."},{"id":"c","label":"Assume it is wrong and discard it","is_correct":false,"explanation":"Too far. The point is to verify, not to reject everything out of hand."}]}$lum$::jsonb, NULL),
  ($lum$492db5d1-c19b-5a2c-bad1-7b9157ecc3f0$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Which kind of AI output most deserves your scrutiny because the error is easy to miss?","options":[{"id":"a","label":"An obviously garbled sentence","is_correct":false,"explanation":"An obvious mistake trips your alarm. It is the subtle one that slips through."},{"id":"b","label":"A fluent, plausible answer with one wrong detail buried in it","is_correct":true,"explanation":"A confident wrong answer is more dangerous than an obvious one, because it does not look wrong."},{"id":"c","label":"A response that says it is not sure","is_correct":false,"explanation":"An honest hedge is a signal to check, which is helpful, not the hidden risk."}]}$lum$::jsonb, NULL),
  ($lum$fd6dc2b5-1d31-5cb9-8d7d-9e9d86a9a1fb$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You want help with a sensitive document at work. What is the safe way to use a public AI tool?","options":[{"id":"a","label":"Paste it in as is, since the chat is private to you","is_correct":false,"explanation":"A public tool is an outside service. Sensitive details should not go in raw."},{"id":"b","label":"Remove names and identifying details first, or use a tool your organization has approved","is_correct":true,"explanation":"Genericize for public tools, or keep confidential work in an approved tool."},{"id":"c","label":"Paste it and tell the AI to keep it confidential","is_correct":false,"explanation":"An instruction does not control the service's data policy. The data is still exposed."}]}$lum$::jsonb, NULL),
  ($lum$c1d6a503-289e-580e-bc93-d54b8f08ee54$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Your colleague wrongly accuses your genuinely human-written report of being AI-generated. What is the strongest response?","options":[{"id":"a","label":"Run it through an AI-detector and accept whatever it says","is_correct":false,"explanation":"AI detectors are unreliable and flag real human writing. They are not proof."},{"id":"b","label":"Show your process: drafts, version history, notes, and your ability to explain the content","is_correct":true,"explanation":"Evidence of how you made it, plus deep familiarity with it, is the real defense."},{"id":"c","label":"Rewrite the whole thing to sound less polished","is_correct":false,"explanation":"Dumbing down your work to dodge a false accusation is the wrong fix."}]}$lum$::jsonb, NULL),
  ($lum$6ab7182f-f5bd-5aaf-a636-efcaa057a437$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"What is the difference between using AI authentically and using it lazily?","options":[{"id":"a","label":"Authentic use means you stay the author: you direct it, edit it, and stand behind the result as your own","is_correct":true,"explanation":"Integrity is about ownership and judgment, not about whether a tool was involved."},{"id":"b","label":"Authentic use means never editing what the AI produces","is_correct":false,"explanation":"The opposite. Pasting raw output unread is the lazy version."},{"id":"c","label":"There is no difference as long as the output is good","is_correct":false,"explanation":"Whether you actually engaged with and own the work is exactly the difference."}]}$lum$::jsonb, NULL),
  ($lum$781c3b3b-1d15-5094-805e-86f9ddb2d570$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Your team wants consistent quality from AI across everyone. What helps most?","options":[{"id":"a","label":"Let each person invent their own prompts privately every time","is_correct":false,"explanation":"That produces wildly varied quality. Shared, saved prompts keep output consistent."},{"id":"b","label":"Agree on shared prompts and a light policy for what is and is not okay to use AI for","is_correct":true,"explanation":"Shared standards and saved prompts make a team's AI use consistent and safe."},{"id":"c","label":"Ban AI entirely so no one uses it differently","is_correct":false,"explanation":"A blanket ban throws away the value. Consistency comes from shared practice."}]}$lum$::jsonb, NULL),
  ($lum$01fc9789-196f-5af3-8e0e-7458a733ba1a$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"Before relying on a specific fact, statistic, or source from AI, you should always {{1}} it against a real source, because the tool can state a wrong answer with full confidence.","blanks":[{"id":"1","accept":["verify","check","confirm"],"ideal":"verify"}],"explanation":"Verification is the core habit of working well with AI: confident does not mean correct."}$lum$::jsonb, NULL),
  ($lum$9945fcef-0ff7-51fb-b34c-a01092172de2$lum$::uuid, $lum$f52084a4-b34f-5574-aaaf-b829878f1f57$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"To use AI with integrity, you stay the {{1}} of the work: you direct it, edit it, and stand behind the result as your own.","blanks":[{"id":"1","accept":["author","owner"],"ideal":"author"}],"explanation":"Ownership is what separates authentic use from lazy pasting."}$lum$::jsonb, NULL),
  ($lum$437e1488-1b82-5b28-a696-0c129c8cca9c$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"You notice the AI agrees with almost everything you propose, even weak ideas. What is happening, and what should you do?","options":[{"id":"a","label":"It is sycophancy: the model tends to agree with you, so ask it to argue the opposite case","is_correct":true,"explanation":"Models lean toward agreeing. Deliberately asking for the counter-case restores real pressure-testing."},{"id":"b","label":"It means your ideas are all genuinely strong, so proceed","is_correct":false,"explanation":"Agreement from AI is not validation. It often just mirrors what you want to hear."},{"id":"c","label":"It is broken and should be ignored entirely","is_correct":false,"explanation":"It is a known tendency you can work around, not a malfunction."}]}$lum$::jsonb, NULL),
  ($lum$5cf60f6e-3ad1-5d42-9516-6ff9d6d95c8b$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What does it mean to avoid outsourcing your thinking to AI?","options":[{"id":"a","label":"Never using AI to help you think through anything","is_correct":false,"explanation":"AI can help you think. The risk is letting it think instead of you."},{"id":"b","label":"Forming your own view and using AI to test and sharpen it, not to hand over the decision","is_correct":true,"explanation":"You stay the one reasoning. AI is a sounding board, not a substitute for your judgment."},{"id":"c","label":"Always doing the opposite of what the AI suggests","is_correct":false,"explanation":"Reflexively disagreeing is just outsourcing in reverse. The point is to keep your own judgment active."}]}$lum$::jsonb, NULL),
  ($lum$692fedf0-a8ce-5c74-acb3-e1fc5c6033ea$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You used AI to help write a board memo. When should you disclose that you used it?","options":[{"id":"a","label":"Always, in full detail, for every routine email","is_correct":false,"explanation":"Blanket disclosure of routine help is usually unnecessary. Context and norms matter."},{"id":"b","label":"When it matters to the audience or is expected: authorship claims, graded work, or where AI use changes how the work should be judged","is_correct":true,"explanation":"Disclose where it affects trust, authorship, or the rules you are operating under."},{"id":"c","label":"Never, since how you made it is nobody's business","is_correct":false,"explanation":"In contexts where AI use is material or expected, hiding it breaks trust."}]}$lum$::jsonb, NULL),
  ($lum$15cbbca7-2886-59d6-8ac5-c8ff371dae2a$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"An AI-assisted report you sent out contained an error. Who is responsible?","options":[{"id":"a","label":"The AI, since it produced the mistake","is_correct":false,"explanation":"Accountability does not transfer to a tool. You sent it, you own it."},{"id":"b","label":"You, because you put your name on it and chose to send it","is_correct":true,"explanation":"You own the output you release, regardless of how it was drafted. Own the error and fix it."},{"id":"c","label":"No one, since AI mistakes are unavoidable","is_correct":false,"explanation":"The mistake is avoidable through your review, and the responsibility is yours."}]}$lum$::jsonb, NULL),
  ($lum$838050c2-698c-5d48-bd7d-f91a1b3c9ea2$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"Why set personal limits on where you will and will not use AI?","options":[{"id":"a","label":"Because AI is too dangerous to use for anything important","is_correct":false,"explanation":"Limits are about judgment, not fear. AI is useful within the right boundaries."},{"id":"b","label":"Because some tasks demand your own judgment, values, or human presence, and naming those lines keeps you in control","is_correct":true,"explanation":"Deciding your boundaries ahead of time keeps you deliberate rather than drifting."},{"id":"c","label":"Because your employer requires you to never think about it again","is_correct":false,"explanation":"Personal limits are your own considered choices, not a one-time rule to forget."}]}$lum$::jsonb, NULL),
  ($lum$a3fb76dc-b9de-5a28-9cf2-b6cbd2938d16$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"How should you watch for bias in AI output?","options":[{"id":"a","label":"Assume the AI is perfectly neutral because it is a machine","is_correct":false,"explanation":"AI reflects patterns in its training data and can carry bias. Neutrality is not guaranteed."},{"id":"b","label":"Stay alert that its output can reflect skewed assumptions, and check important decisions against other perspectives","is_correct":true,"explanation":"Treating AI as potentially biased and cross-checking keeps your judgment in charge."},{"id":"c","label":"Trust it more on sensitive topics than on simple ones","is_correct":false,"explanation":"Sensitive topics are exactly where hidden bias does the most harm. Scrutinize them more, not less."}]}$lum$::jsonb, NULL),
  ($lum$d1634928-b4eb-5bc3-b9f9-6020fbbfaf42$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"When AI keeps agreeing with you, called {{1}}, a good fix is to ask it to make the strongest case against your idea.","blanks":[{"id":"1","accept":["sycophancy","agreement"],"ideal":"sycophancy"}],"explanation":"Naming the tendency lets you counter it by forcing the opposing view."}$lum$::jsonb, NULL),
  ($lum$ca1d341e-1cc8-556c-a73a-64e7c62b00a3$lum$::uuid, $lum$f7a4aab4-30d4-5927-9bae-f5c092cc8e8b$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"No matter how a document was drafted, you are {{1}} for the work you put your name on and send.","blanks":[{"id":"1","accept":["responsible","accountable"],"ideal":"responsible"}],"explanation":"Accountability stays with the human, never the tool."}$lum$::jsonb, NULL)
